import { AsyncBuffer, cachedAsyncBuffer } from "hyparquet";

export const PUBLIC_UPLOADS_BASE = "https://uploads.seasketch.org";

export interface R2FileSource {
  /** hyparquet-compatible buffer performing R2 range reads */
  buffer: AsyncBuffer;
  byteLength: number;
  etag: string;
}

export interface OpenFileOptions {
  bucket: R2Bucket;
  key: string;
  /** When true, fetch over https from the public uploads domain instead of the binding. */
  dev: boolean;
  /** When false (DEV mode), skip caches.default for range reads. */
  cacheEnabled: boolean;
  waitUntil: (promise: Promise<unknown>) => void;
}

/**
 * Opens a file in R2 as a hyparquet AsyncBuffer. Each range read is cached in
 * caches.default keyed by object etag, so repeated queries against the same
 * table skip R2 entirely for the footer and hot column chunks.
 *
 * Returns null if the object does not exist.
 */
export async function openR2File(
  options: OpenFileOptions
): Promise<R2FileSource | null> {
  const { bucket, key, dev, cacheEnabled, waitUntil } = options;

  let byteLength: number;
  let etag: string;
  if (dev) {
    // The public CDN does not reliably include content-length on HEAD
    // responses, so use a 1-byte range request and read the total size from
    // the content-range header (e.g. "bytes 0-0/1086796").
    const probe = await fetch(`${PUBLIC_UPLOADS_BASE}/${key}`, {
      headers: { Range: "bytes=0-0" },
    });
    if (!probe.ok) {
      return null;
    }
    const contentRange = probe.headers.get("content-range") || "";
    byteLength = Number(contentRange.split("/")[1] || 0);
    etag = probe.headers.get("etag") || "";
    if (!byteLength) {
      return null;
    }
  } else {
    const head = await bucket.head(key);
    if (!head) {
      return null;
    }
    byteLength = head.size;
    etag = head.httpEtag;
  }

  const slice = async (start: number, end?: number): Promise<ArrayBuffer> => {
    const rangeEnd = end === undefined ? byteLength : end;
    if (rangeEnd <= start) {
      return new ArrayBuffer(0);
    }
    // Synthetic, versioned cache key for this byte range.
    const cacheKey = new Request(
      `${PUBLIC_UPLOADS_BASE}/${key}?etag=${encodeURIComponent(
        etag
      )}&bytes=${start}-${rangeEnd - 1}`
    );
    if (cacheEnabled) {
      const cached = await caches.default.match(cacheKey);
      if (cached) {
        return await cached.arrayBuffer();
      }
    }

    let data: ArrayBuffer;
    if (dev) {
      const res = await fetch(`${PUBLIC_UPLOADS_BASE}/${key}`, {
        headers: { Range: `bytes=${start}-${rangeEnd - 1}` },
      });
      if (!res.ok) {
        throw new Error(
          `Range request for ${key} failed with status ${res.status}`
        );
      }
      data = await res.arrayBuffer();
    } else {
      const body = await bucket.get(key, {
        range: { offset: start, length: rangeEnd - start },
      });
      if (!body) {
        throw new Error(`Range request to R2 for ${key} returned no body`);
      }
      data = await body.arrayBuffer();
    }

    if (cacheEnabled) {
      waitUntil(
        caches.default.put(
          cacheKey,
          new Response(data.slice(0), {
            status: 200,
            headers: {
              "Content-Type": "application/octet-stream",
              "Cache-Control": "public, max-age=86400",
            },
          })
        )
      );
    }
    return data;
  };

  // cachedAsyncBuffer memoizes identical slice() calls within this request.
  const buffer = cachedAsyncBuffer({ byteLength, slice });
  return { buffer, byteLength, etag };
}

/**
 * Fetches a whole (small) file from R2, e.g. column-stats.json.
 * Returns null if missing.
 */
export async function getR2Object(
  options: Pick<OpenFileOptions, "bucket" | "key" | "dev">
): Promise<ArrayBuffer | null> {
  const { bucket, key, dev } = options;
  if (dev) {
    const res = await fetch(`${PUBLIC_UPLOADS_BASE}/${key}`);
    if (!res.ok) {
      return null;
    }
    return await res.arrayBuffer();
  }
  const body = await bucket.get(key);
  if (!body) {
    return null;
  }
  return await body.arrayBuffer();
}
